INSERT INTO migration.p6_article_source (id, payload) VALUES
  ('art-001', '{"id":"art-001","title":"露營新手指南：如何選擇適合自己的帳篷","category":"新手教學","author":"Amy 露營教練","authorAvatar":"https://picsum.photos/seed/author1/40/40","publishedDate":"2026-03-15","readTime":8,"image":"https://picsum.photos/seed/article1/800/450","excerpt":"第一次露營，面對琳琅滿目的帳篷品牌和型號，你是否也感到茫然？本篇整理了選擇帳篷前必須考慮的 5 大關鍵因素，讓你第一次就買對！","tags":["新手","帳篷","購買指南"],"isFeatured":true,"relatedProducts":["P001","P010","P018"],"content":[{"type":"text","value":"帳篷是露營裝備中最重要的投資，選對了可以陪伴你走遍山林，選錯了可能讓你的露營體驗大打折扣。以下是我在帶過數百場露營課程後，整理出的五大選購關鍵。"},{"type":"heading","value":"1. 容納人數：不要只看標示"},{"type":"text","value":"帳篷標示的「2人帳」往往只是剛好塞下兩個睡袋的尺寸，幾乎沒有額外空間。建議有兩人使用時選擇「3人帳」，家庭露營（4人）則選「6人帳」，才能有舒適的移動空間。"},{"type":"product","productId":"P001"},{"type":"heading","value":"2. 防水係數：台灣多雨環境的必要考量"},{"type":"text","value":"台灣山區雨量充沛，建議選擇防水係數（耐水壓）至少 2000mm 以上的帳篷。如果常在高山露營，建議 3000mm 以上。外帳縫線部分務必確認是否有防水膠條處理。"},{"type":"heading","value":"3. 重量：你真的需要超輕嗎？"},{"type":"text","value":"輕量帳篷通常售價昂貴，如果只是車泊（汽車露營），1-2kg 的重量差異其實不重要。只有在需要長途徒步的場景，輕量化才是優先考量。"},{"type":"product","productId":"P010"},{"type":"heading","value":"4. 通風設計：悶熱才是夏天最大的敵人"},{"type":"text","value":"夏天露營，帳篷的通風比保暖更重要。尋找有前後通風口、內帳以網布為主的設計，可以有效降低帳內溫度，讓你在悶熱的夏夜也能舒適入眠。"},{"type":"heading","value":"5. 搭建難度：建議現場試搭"},{"type":"text","value":"購買前若可以在門市試搭是最理想的。網路購買時，可以搜尋 YouTube 搭建教學影片，評估是否在天黑、疲憊的狀態下也能搭建完成。"}]}'::jsonb),
  ('art-002', '{"id":"art-002","title":"2026 春季露營景點推薦：台灣最美五大營地","category":"景點推薦","author":"Tom 資深露友","authorAvatar":"https://picsum.photos/seed/author2/40/40","publishedDate":"2026-03-20","readTime":6,"image":"https://picsum.photos/seed/article2/800/450","excerpt":"春暖花開，正是露營的黃金季節！我們精選了台灣五個各具特色的營地，有夜景美景、有林間靜謐，更有親子友善設施，讓你週末說走就走。","tags":["景點","春季","台灣"],"isFeatured":false,"relatedProducts":["P007","P016"],"content":[{"type":"text","value":"春天是露營最舒適的季節，氣候宜人，蟲蟲還未大量出沒。以下是我今年走訪過的五個值得推薦的營地。"},{"type":"heading","value":"1. 合歡山頂高山帳篷區"},{"type":"text","value":"海拔 3275 公尺的合歡山，夜晚星空之美無與倫比。需要提前申請入場，裝備必須能應對低溫（夜晚可能低至 5°C 以下）。建議攜帶 -5°C 等級睡袋。"},{"type":"product","productId":"P004"},{"type":"heading","value":"2. 福隆海水浴場海景營地"},{"type":"text","value":"可以一邊聽海浪聲入眠的海景營地，交通便利（距台北約一小時），設施完善，適合親子家庭。建議攜帶大型天幕帳遮陽。"},{"type":"product","productId":"P018"}]}'::jsonb),
  ('art-003', '{"id":"art-003","title":"露營廚藝升級：如何用瓦斯爐做出星級料理","category":"生活技巧","author":"Jenny 美食露友","authorAvatar":"https://picsum.photos/seed/author3/40/40","publishedDate":"2026-04-01","readTime":10,"image":"https://picsum.photos/seed/article3/800/450","excerpt":"誰說戶外料理只能泡麵？只要準備對工具，在營地也能享受媲美餐廳的美食！本篇分享我最常用的 3 道戶外料理食譜和必備炊具清單。","tags":["料理","炊具","生活技巧"],"isFeatured":false,"relatedProducts":["P003","P012"],"content":[{"type":"text","value":"戶外料理是露營體驗中最有趣的部分之一。配合大自然的環境，即使是簡單的料理也會變得格外美味。"},{"type":"heading","value":"必備炊具清單"},{"type":"text","value":"入門露營廚師建議攜帶：輕量化瓦斯爐一台、1.5L 鋁合金鍋一只、折疊式砧板、不鏽鋼刀具組。進階版本則可以考慮鑄鐵鍋和瓦斯雙口爐。"},{"type":"product","productId":"P003"},{"type":"product","productId":"P012"},{"type":"heading","value":"食譜 1：一鍋鮮菇雞肉炊飯"},{"type":"text","value":"食材全部事先在家切好裝袋，到營地只需一個鍋子就能完成。洗米→加入雞腿塊、舞菇、醬油、味醂→大火煮滾→轉小火悶 15 分鐘，起鍋前撒上蔥花即可。"}]}'::jsonb),
  ('art-004', '{"id":"art-004","title":"登山健行裝備完全指南：從頭到腳的清單","category":"裝備評測","author":"Mark 登山嚮導","authorAvatar":"https://picsum.photos/seed/author4/40/40","publishedDate":"2026-04-10","readTime":12,"image":"https://picsum.photos/seed/article4/800/450","excerpt":"計畫人生第一次登山健行？這份從頭到腳的裝備清單，讓你出發前不遺漏任何重要裝備，同時避免過度購買造成背包超重。","tags":["登山","裝備","清單"],"isFeatured":true,"relatedProducts":["P002","P007","P009","P011"],"content":[{"type":"text","value":"登山前的裝備準備是整個旅程最重要的環節。以下依照重要性分類列出必備裝備。"},{"type":"heading","value":"十大必攜裝備（The Ten Essentials）"},{"type":"text","value":"這是登山界公認的安全基本裝備清單：導航工具、頭燈、防曬防護、急救用品、修繕工具、火種、緊急避難工具、食物、飲水、衣物備品。"},{"type":"product","productId":"P009"},{"type":"product","productId":"P002"}]}'::jsonb),
  ('art-005', '{"id":"art-005","title":"輕量化露營入門：如何讓背包重量低於 10kg","category":"新手教學","author":"Amy 露營教練","authorAvatar":"https://picsum.photos/seed/author1/40/40","publishedDate":"2026-04-20","readTime":9,"image":"https://picsum.photos/seed/article5/800/450","excerpt":"輕量化不代表要犧牲舒適度，更不需要花大錢換頂級裝備。透過聰明的裝備選擇和打包技巧，你也能讓背包重量大幅降低。","tags":["輕量化","裝備","背包"],"isFeatured":false,"relatedProducts":["P001","P008","P013"],"content":[{"type":"text","value":"輕量化露營（Ultralight Backpacking）近年越來越受到重視，因為減輕負重不只讓行走更輕鬆，更能讓你在路上欣賞更多風景。"},{"type":"heading","value":"「大三樣」是關鍵"},{"type":"text","value":"背包、帳篷、睡袋被稱為「大三樣」，佔了背包重量的 50-70%。優先投資輕量化的大三樣，效益最高。"},{"type":"product","productId":"P001"},{"type":"product","productId":"P013"}]}'::jsonb),
  ('art-006', '{"id":"art-006","title":"夏季防蟲防曬：戶外活動者的全季節保護攻略","category":"生活技巧","author":"Jenny 美食露友","authorAvatar":"https://picsum.photos/seed/author3/40/40","publishedDate":"2026-05-01","readTime":7,"image":"https://picsum.photos/seed/article6/800/450","excerpt":"夏季戶外活動最大的困擾莫過於蚊蟲叮咬和強烈日曬。本篇整理了實測有效的防蟲防曬策略，讓你夏天露營也能清爽舒適。","tags":["夏季","防蟲","防曬"],"isFeatured":false,"relatedProducts":["P007","P017"],"content":[{"type":"text","value":"夏天露營是很多人的夢想，但炎熱、蚊蟲和強烈紫外線常常成為阻礙。以下幾個策略可以有效提升夏日露營體驗。"},{"type":"heading","value":"防蟲三大法"},{"type":"text","value":"1. 選擇長袖排汗衣：既能防曬又能減少暴露肌膚。2. DEET 成分防蚊液：噴在衣服上效果更好。3. 天幕防蚊帳：讓烹飪和用餐空間完全隔絕蚊蟲。"},{"type":"product","productId":"P017"}]}'::jsonb);
