  ('REV033', 'U036', 'P024', 'v-P024-0', 'v-P024-0', '彭心怡', '/assets/images/avatar-01.jpg', '碳纖維登山杖', 5, '登山杖輕量穩固，八月爬山必備。', '2026-07-15 09:20:00'::timestamp AT TIME ZONE 'Asia/Taipei', 'NO_ORDER_ID: source review cannot be tied to an authoritative purchase'),
  ('REV034', 'U043', 'P009', 'v-P009-0', 'v-P009-0', '范冠霖', '/assets/images/avatar-02.jpg', '折疊桌椅組', 4, '桌椅組收納方便，家庭露營很實用。', '2026-07-25 16:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', 'NO_ORDER_ID: source review cannot be tied to an authoritative purchase'),
  ('REV035', 'U047', 'P013', 'v-P013-0', 'v-P013-0', '袁宇翔', '/assets/images/avatar-03.jpg', '折疊蛋捲桌', 5, '八月促銷入手，CP 值很高！', '2026-08-12 11:45:00'::timestamp AT TIME ZONE 'Asia/Taipei', 'NO_ORDER_ID: source review cannot be tied to an authoritative purchase'),
  ('REV036', 'U049', 'P016', 'v-P016-0', 'v-P016-0', '許柏均', '/assets/images/avatar-02.jpg', '65L 重裝背包', 4, '爐具火力足，中秋烤肉露營剛好。', '2026-08-28 10:10:00'::timestamp AT TIME ZONE 'Asia/Taipei', 'NO_ORDER_ID: source review cannot be tied to an authoritative purchase'),
