INSERT INTO articles_p6 (id, title, category, author, author_avatar_url, published_at, summary, cover_image_url, reading_minutes, featured, status, created_at, updated_at) VALUES
  ('art-001', '露營新手指南：如何選擇適合自己的帳篷', '新手教學', 'Amy 露營教練', 'https://picsum.photos/seed/author1/40/40', '2026-03-15 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '第一次露營，面對琳琅滿目的帳篷品牌和型號，你是否也感到茫然？本篇整理了選擇帳篷前必須考慮的 5 大關鍵因素，讓你第一次就買對！', 'https://picsum.photos/seed/article1/800/450', 8, TRUE, 'published', '2026-03-15 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '2026-03-15 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei'),
  ('art-002', '2026 春季露營景點推薦：台灣最美五大營地', '景點推薦', 'Tom 資深露友', 'https://picsum.photos/seed/author2/40/40', '2026-03-20 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '春暖花開，正是露營的黃金季節！我們精選了台灣五個各具特色的營地，有夜景美景、有林間靜謐，更有親子友善設施，讓你週末說走就走。', 'https://picsum.photos/seed/article2/800/450', 6, FALSE, 'published', '2026-03-20 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '2026-03-20 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei'),
  ('art-003', '露營廚藝升級：如何用瓦斯爐做出星級料理', '生活技巧', 'Jenny 美食露友', 'https://picsum.photos/seed/author3/40/40', '2026-04-01 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '誰說戶外料理只能泡麵？只要準備對工具，在營地也能享受媲美餐廳的美食！本篇分享我最常用的 3 道戶外料理食譜和必備炊具清單。', 'https://picsum.photos/seed/article3/800/450', 10, FALSE, 'published', '2026-04-01 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '2026-04-01 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei'),
  ('art-004', '登山健行裝備完全指南：從頭到腳的清單', '裝備評測', 'Mark 登山嚮導', 'https://picsum.photos/seed/author4/40/40', '2026-04-10 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '計畫人生第一次登山健行？這份從頭到腳的裝備清單，讓你出發前不遺漏任何重要裝備，同時避免過度購買造成背包超重。', 'https://picsum.photos/seed/article4/800/450', 12, TRUE, 'published', '2026-04-10 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '2026-04-10 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei'),
  ('art-005', '輕量化露營入門：如何讓背包重量低於 10kg', '新手教學', 'Amy 露營教練', 'https://picsum.photos/seed/author1/40/40', '2026-04-20 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '輕量化不代表要犧牲舒適度，更不需要花大錢換頂級裝備。透過聰明的裝備選擇和打包技巧，你也能讓背包重量大幅降低。', 'https://picsum.photos/seed/article5/800/450', 9, FALSE, 'published', '2026-04-20 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '2026-04-20 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei'),
  ('art-006', '夏季防蟲防曬：戶外活動者的全季節保護攻略', '生活技巧', 'Jenny 美食露友', 'https://picsum.photos/seed/author3/40/40', '2026-05-01 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '夏季戶外活動最大的困擾莫過於蚊蟲叮咬和強烈日曬。本篇整理了實測有效的防蟲防曬策略，讓你夏天露營也能清爽舒適。', 'https://picsum.photos/seed/article6/800/450', 7, FALSE, 'published', '2026-05-01 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei', '2026-05-01 00:00:00'::timestamp AT TIME ZONE 'Asia/Taipei');
