INSERT INTO article_content_blocks_p6 (id, article_id, sort_order, block_type, text_content, product_id) VALUES
  (1, 'art-001', 0, 'text', '帳篷是露營裝備中最重要的投資，選對了可以陪伴你走遍山林，選錯了可能讓你的露營體驗大打折扣。以下是我在帶過數百場露營課程後，整理出的五大選購關鍵。', NULL),
  (2, 'art-001', 1, 'heading', '1. 容納人數：不要只看標示', NULL),
  (3, 'art-001', 2, 'text', '帳篷標示的「2人帳」往往只是剛好塞下兩個睡袋的尺寸，幾乎沒有額外空間。建議有兩人使用時選擇「3人帳」，家庭露營（4人）則選「6人帳」，才能有舒適的移動空間。', NULL),
  (4, 'art-001', 3, 'product', NULL, 'P001'),
  (5, 'art-001', 4, 'heading', '2. 防水係數：台灣多雨環境的必要考量', NULL),
  (6, 'art-001', 5, 'text', '台灣山區雨量充沛，建議選擇防水係數（耐水壓）至少 2000mm 以上的帳篷。如果常在高山露營，建議 3000mm 以上。外帳縫線部分務必確認是否有防水膠條處理。', NULL),
  (7, 'art-001', 6, 'heading', '3. 重量：你真的需要超輕嗎？', NULL),
  (8, 'art-001', 7, 'text', '輕量帳篷通常售價昂貴，如果只是車泊（汽車露營），1-2kg 的重量差異其實不重要。只有在需要長途徒步的場景，輕量化才是優先考量。', NULL),
  (9, 'art-001', 8, 'product', NULL, 'P010'),
  (10, 'art-001', 9, 'heading', '4. 通風設計：悶熱才是夏天最大的敵人', NULL),
  (11, 'art-001', 10, 'text', '夏天露營，帳篷的通風比保暖更重要。尋找有前後通風口、內帳以網布為主的設計，可以有效降低帳內溫度，讓你在悶熱的夏夜也能舒適入眠。', NULL),
  (12, 'art-001', 11, 'heading', '5. 搭建難度：建議現場試搭', NULL),
  (13, 'art-001', 12, 'text', '購買前若可以在門市試搭是最理想的。網路購買時，可以搜尋 YouTube 搭建教學影片，評估是否在天黑、疲憊的狀態下也能搭建完成。', NULL),
  (14, 'art-002', 0, 'text', '春天是露營最舒適的季節，氣候宜人，蟲蟲還未大量出沒。以下是我今年走訪過的五個值得推薦的營地。', NULL),
  (15, 'art-002', 1, 'heading', '1. 合歡山頂高山帳篷區', NULL),
  (16, 'art-002', 2, 'text', '海拔 3275 公尺的合歡山，夜晚星空之美無與倫比。需要提前申請入場，裝備必須能應對低溫（夜晚可能低至 5°C 以下）。建議攜帶 -5°C 等級睡袋。', NULL),
  (17, 'art-002', 3, 'product', NULL, 'P004'),
  (18, 'art-002', 4, 'heading', '2. 福隆海水浴場海景營地', NULL),
  (19, 'art-002', 5, 'text', '可以一邊聽海浪聲入眠的海景營地，交通便利（距台北約一小時），設施完善，適合親子家庭。建議攜帶大型天幕帳遮陽。', NULL),
  (20, 'art-002', 6, 'product', NULL, 'P018'),
  (21, 'art-003', 0, 'text', '戶外料理是露營體驗中最有趣的部分之一。配合大自然的環境，即使是簡單的料理也會變得格外美味。', NULL),
  (22, 'art-003', 1, 'heading', '必備炊具清單', NULL),
  (23, 'art-003', 2, 'text', '入門露營廚師建議攜帶：輕量化瓦斯爐一台、1.5L 鋁合金鍋一只、折疊式砧板、不鏽鋼刀具組。進階版本則可以考慮鑄鐵鍋和瓦斯雙口爐。', NULL),
  (24, 'art-003', 3, 'product', NULL, 'P003'),
  (25, 'art-003', 4, 'product', NULL, 'P012'),
  (26, 'art-003', 5, 'heading', '食譜 1：一鍋鮮菇雞肉炊飯', NULL),
  (27, 'art-003', 6, 'text', '食材全部事先在家切好裝袋，到營地只需一個鍋子就能完成。洗米→加入雞腿塊、舞菇、醬油、味醂→大火煮滾→轉小火悶 15 分鐘，起鍋前撒上蔥花即可。', NULL),
  (28, 'art-004', 0, 'text', '登山前的裝備準備是整個旅程最重要的環節。以下依照重要性分類列出必備裝備。', NULL),
  (29, 'art-004', 1, 'heading', '十大必攜裝備（The Ten Essentials）', NULL),
  (30, 'art-004', 2, 'text', '這是登山界公認的安全基本裝備清單：導航工具、頭燈、防曬防護、急救用品、修繕工具、火種、緊急避難工具、食物、飲水、衣物備品。', NULL),
  (31, 'art-004', 3, 'product', NULL, 'P009'),
  (32, 'art-004', 4, 'product', NULL, 'P002'),
  (33, 'art-005', 0, 'text', '輕量化露營（Ultralight Backpacking）近年越來越受到重視，因為減輕負重不只讓行走更輕鬆，更能讓你在路上欣賞更多風景。', NULL),
  (34, 'art-005', 1, 'heading', '「大三樣」是關鍵', NULL),
  (35, 'art-005', 2, 'text', '背包、帳篷、睡袋被稱為「大三樣」，佔了背包重量的 50-70%。優先投資輕量化的大三樣，效益最高。', NULL),
  (36, 'art-005', 3, 'product', NULL, 'P001'),
  (37, 'art-005', 4, 'product', NULL, 'P013'),
  (38, 'art-006', 0, 'text', '夏天露營是很多人的夢想，但炎熱、蚊蟲和強烈紫外線常常成為阻礙。以下幾個策略可以有效提升夏日露營體驗。', NULL),
  (39, 'art-006', 1, 'heading', '防蟲三大法', NULL),
  (40, 'art-006', 2, 'text', '1. 選擇長袖排汗衣：既能防曬又能減少暴露肌膚。2. DEET 成分防蚊液：噴在衣服上效果更好。3. 天幕防蚊帳：讓烹飪和用餐空間完全隔絕蚊蟲。', NULL),
  (41, 'art-006', 3, 'product', NULL, 'P017');
